      [Service]
      ExecStart=
      ExecStart=/bin/bash -c '/usr/local/bin/wg-mesh-enroll.sh || true'
      RemainAfterExit=yes

  - path: /etc/nginx/sites-available/dht-proxy
    permissions: '0644'
    content: |
      server {
          listen 80 default_server;
          listen [::]:80 default_server;
          server_name _;
          location = /nginx-health { return 200 ""OK\n""; add_header Content-Type text/plain; }
          location / {
              proxy_pass http://127.0.0.1:8080;
              proxy_set_header Host $host;
              proxy_set_header X-Real-IP $remote_addr;
              proxy_connect_timeout 5s;
              proxy_read_timeout 35s;
          }
      }

  # Inline watchdog script (small, static, no placeholder pattern)
  - path: /usr/local/bin/wg-mesh-watchdog.sh
    permissions: '0755'
    content: |
      #!/bin/bash
      WG_INTERFACE=""wg-mesh""
      STALE_THRESHOLD=180
      if ! wg show ""$WG_INTERFACE"" &>/dev/null; then
          /usr/local/bin/wg-mesh-enroll.sh; exit 0
      fi
      LAST_HANDSHAKE=$(wg show ""$WG_INTERFACE"" latest-handshakes 2>/dev/null | awk '{print $2}' | head -1)
      NOW=$(date +%s)
      AGE=$(( NOW - ${LAST_HANDSHAKE:-0} ))
      if [ ""${LAST_HANDSHAKE:-0}"" -eq 0 ] || [ ""$AGE"" -gt ""$STALE_THRESHOLD"" ]; then
          echo ""[wg-watchdog] Handshake stale (${AGE}s) — re-enrolling""
          /usr/local/bin/wg-mesh-enroll.sh
      fi

runcmd:
  - ln -sf /lib/systemd/system/qemu-guest-agent.service /etc/systemd/system/multi-user.target.wants/qemu-guest-agent.service
  - systemctl start qemu-guest-agent || true

  # ── Identity (from obligation state API — persistent across redeployments) ──
  - |
    echo ""Fetching DHT identity from obligation state...""
    ATTEMPTS=0
    IDENTITY=""""
    while [ $ATTEMPTS -lt 24 ] && [ -z ""$IDENTITY"" ]; do
      IDENTITY=$(curl -sf --max-time 5 http://192.168.122.1:5100/api/obligations/dht/state 2>/dev/null || echo """")
      [ -z ""$IDENTITY"" ] && sleep 5 && ATTEMPTS=$((ATTEMPTS+1))
    done
    [ -z ""$IDENTITY"" ] && echo ""FATAL: DHT identity unavailable"" && exit 1
    mkdir -p /var/lib/decloud-dht && chmod 700 /var/lib/decloud-dht
    echo ""$IDENTITY"" | jq -r '.ed25519PrivateKeyBase64' | base64 -d > /var/lib/decloud-dht/identity.key
    chmod 600 /var/lib/decloud-dht/identity.key

  # ── Artifacts from local cache (pre-fetched by node agent before deploy) ──
  - curl -sf ${ARTIFACT_URL:dht-node} -o /usr/local/bin/dht-node
  - echo ""${ARTIFACT_SHA256:dht-node}  /usr/local/bin/dht-node"" | sha256sum -c -
  - chmod +x /usr/local/bin/dht-node

  - curl -sf ${ARTIFACT_URL:wg-mesh-enroll} -o /usr/local/bin/wg-mesh-enroll.sh && chmod +x /usr/local/bin/wg-mesh-enroll.sh
  - curl -sf ${ARTIFACT_URL:wg-config-fetch} -o /usr/local/bin/wg-config-fetch.sh && chmod +x /usr/local/bin/wg-config-fetch.sh
  - curl -sf ${ARTIFACT_URL:dht-health-check} -o /usr/local/bin/dht-health-check.sh && chmod +x /usr/local/bin/dht-health-check.sh
  - curl -sf ${ARTIFACT_URL:dht-notify-ready} -o /usr/local/bin/dht-notify-ready.sh && chmod +x /usr/local/bin/dht-notify-ready.sh
  - curl -sf ${ARTIFACT_URL:dht-bootstrap-poll} -o /usr/local/bin/dht-bootstrap-poll.sh && chmod +x /usr/local/bin/dht-bootstrap-poll.sh
  - mkdir -p /opt/decloud-dht/static
  - curl -sf ${ARTIFACT_URL:dht-dashboard} -o /opt/decloud-dht/dht-dashboard.py && chmod +x /opt/decloud-dht/dht-dashboard.py
  - curl -sf ${ARTIFACT_URL:dht-dashboard-html} -o /opt/decloud-dht/static/dashboard.html
  - curl -sf ${ARTIFACT_URL:dht-dashboard-css} -o /opt/decloud-dht/static/dashboard.css
  - curl -sf ${ARTIFACT_URL:dht-dashboard-js} -o /opt/decloud-dht/static/dashboard.js

  # ── WireGuard mesh enrollment ──────────────────────────────────────────
  - |
    export DECLOUD_ROLE=dht
    export NODE_ID=__NODE_ID__
    export VM_ID=__VM_ID__
    /usr/local/bin/wg-config-fetch.sh

  - mkdir -p /var/lib/decloud-dht
  - systemctl daemon-reload
  - ln -sf /etc/nginx/sites-available/dht-proxy /etc/nginx/sites-enabled/
  - rm -f /etc/nginx/sites-enabled/default
  - nginx -t && systemctl enable nginx && systemctl restart nginx
  - systemctl enable decloud-dht && systemctl start decloud-dht
  - systemctl enable decloud-dht-dashboard && systemctl start decloud-dht-dashboard
  - systemctl enable decloud-dht-bootstrap-poll && systemctl start decloud-dht-bootstrap-poll
  - systemctl enable wg-mesh-watchdog.timer && systemctl start wg-mesh-watchdog.timer
  - 'echo ""DHT node __VM_ID__ ready at $(date) — region: __DHT_REGION__"" >> /var/log/dht-bootstrap.log'

final_message: ""DeCloud DHT Node __VM_NAME__ is ready!""
";

    private const string BLOCKSTORE_CLOUD_INIT = @"
#cloud-config
# DeCloud Block Store VM Cloud-Init Configuration
# Runs a libp2p BitSwap block store node for content-addressed storage.
# Version: 3.0 (artifact-cache model — scripts and binary via artifact pipeline)

hostname: __HOSTNAME__
manage_etc_hosts: true

package_update: false
package_upgrade: false

bootcmd:
  - rm -f /etc/machine-id /var/lib/dbus/machine-id
  - systemd-machine-id-setup
  # Mask snapd/LXD — unused in system VMs, adds ~50s boot delay
  - systemctl mask snapd.service snapd.socket snapd.seeded.service snap.lxd.activate.service lxd.service lxd-agent.service 2>/dev/null || true
  # Start qemu-guest-agent early, independent of runcmd
  - systemctl start qemu-guest-agent 2>/dev/null || true

disable_root: false

__SSH_AUTHORIZED_KEYS_BLOCK__

ssh_pwauth: false

# =====================================================
# SYSTEM PACKAGES
# =====================================================
packages:
  - qemu-guest-agent
  - curl
  - jq
  - openssl
  - nginx-light
  - wireguard
  - wireguard-tools
  - python3

# =====================================================
# SYSTEM CONFIGURATION
# =====================================================
write_files:
  # Environment file (read by systemd EnvironmentFile)
  - path: /etc/decloud-blockstore/blockstore.env
    permissions: '0640'
    content: |
      BLOCKSTORE_LISTEN_PORT=__BLOCKSTORE_LISTEN_PORT__
      BLOCKSTORE_API_PORT=__BLOCKSTORE_API_PORT__
      BLOCKSTORE_ADVERTISE_IP=__BLOCKSTORE_ADVERTISE_IP__
      # BLOCKSTORE_STORAGE_BYTES intentionally omitted — binary fetches from NodeAgent obligation state
      BLOCKSTORE_NODE_ID=__NODE_ID__
      BLOCKSTORE_VM_ID=__VM_ID__
      ORCHESTRATOR_URL=__ORCHESTRATOR_URL__
      BLOCKSTORE_BOOTSTRAP_PEERS=__BLOCKSTORE_BOOTSTRAP_PEERS__

  # WireGuard mesh environment (consumed by enrollment script)
  - path: /etc/decloud/wg-mesh.env
    permissions: '0600'
    content: |
      WG_RELAY_ENDPOINT=__WG_RELAY_ENDPOINT__
      WG_RELAY_PUBKEY=__WG_RELAY_PUBKEY__
      WG_TUNNEL_IP=__WG_TUNNEL_IP__
      WG_RELAY_API=__WG_RELAY_API__
      WG_INTERFACE=wg-mesh
      WG_PARENT_NODE_ID=__NODE_ID__
      WG_DESCRIPTION=BlockStore-__VM_ID__
      WG_PEER_TYPE=system-vm
      WG_ROLE=blockstore

  # WireGuard mesh watchdog — re-enrolls if handshake goes stale
  - path: /usr/local/bin/wg-mesh-watchdog.sh
    permissions: '0755'
    content: |
      #!/bin/bash
      # Re-enroll if WireGuard handshake has been stale for > 3 minutes.
      # Called by systemd timer every 2 minutes.
      WG_INTERFACE=""wg-mesh""
      STALE_THRESHOLD=180

      if ! wg show ""$WG_INTERFACE"" &>/dev/null; then
          echo ""[wg-watchdog] Interface not up — re-enrolling""
          /usr/local/bin/wg-mesh-enroll.sh
          exit 0
      fi

      LAST_HANDSHAKE=$(wg show ""$WG_INTERFACE"" latest-handshakes 2>/dev/null | awk '{print $2}' | head -1)
      NOW=$(date +%s)
      AGE=$(( NOW - ${LAST_HANDSHAKE:-0} ))

      if [ ""${LAST_HANDSHAKE:-0}"" -eq 0 ] || [ ""$AGE"" -gt ""$STALE_THRESHOLD"" ]; then
          echo ""[wg-watchdog] Handshake stale (${AGE}s) — re-enrolling""
          /usr/local/bin/wg-mesh-enroll.sh
      else
          echo ""[wg-watchdog] Handshake OK (${AGE}s ago)""
      fi

  - path: /etc/systemd/system/wg-mesh-watchdog.service
    permissions: '0644'
    content: |
      [Unit]
      Description=WireGuard Mesh Connectivity Watchdog
      After=wg-quick@wg-mesh.service

      [Service]
      Type=oneshot
      ExecStart=/usr/local/bin/wg-mesh-watchdog.sh
      StandardOutput=journal
      StandardError=journal

  - path: /etc/systemd/system/wg-mesh-watchdog.timer
    permissions: '0644'
    content: |
      [Unit]
      Description=WireGuard Mesh Watchdog Timer
      After=wg-quick@wg-mesh.service

      [Timer]
      OnBootSec=2min
      OnUnitActiveSec=2min
      AccuracySec=30s

      [Install]
      WantedBy=timers.target

  # VM identity files
  - path: /etc/decloud/vm-id
    permissions: '0644'
    content: __VM_ID__

  - path: /etc/decloud/orchestrator-url
    permissions: '0644'
    content: __ORCHESTRATOR_URL__

  # ── Systemd services ─────────────────────────────────────────────

  # Main block store service
  - path: /etc/systemd/system/decloud-blockstore.service
    permissions: '0644'
    content: |
      [Unit]
      Description=DeCloud Block Store Node
      After=network-online.target wg-quick@wg-mesh.service
      Wants=network-online.target wg-quick@wg-mesh.service

      [Service]
      User=root
      EnvironmentFile=/etc/decloud-blockstore/blockstore.env
      ExecStart=/usr/local/bin/blockstore-node
      Restart=always
      RestartSec=5
      StandardOutput=journal
      StandardError=journal
      LimitNOFILE=65536

      # Hardening
      ProtectSystem=strict
      ReadWritePaths=/var/lib/decloud-blockstore
      NoNewPrivileges=true

      [Install]
      WantedBy=multi-user.target

  # systemd drop-in: make wg-quick@wg-mesh idempotent
  # Prevents ""already exists"" failure if the interface was brought up
  # outside of systemd (e.g., during cloud-init enrollment).
  - path: /etc/systemd/system/wg-quick@wg-mesh.service.d/override.conf
    permissions: '0644'
    content: |
      [Service]
      ExecStart=
      ExecStart=/bin/bash -c '/usr/local/bin/wg-mesh-enroll.sh || true'
      RemainAfterExit=yes

  # Dashboard server (Python — serves UI and proxies API to Go binary)
  - path: /etc/systemd/system/decloud-blockstore-dashboard.service
    permissions: '0644'
    content: |
      [Unit]
      Description=DeCloud Block Store Dashboard Server
      After=decloud-blockstore.service nginx.service
      Wants=decloud-blockstore.service nginx.service

      [Service]
      Type=simple
      EnvironmentFile=/etc/decloud-blockstore/blockstore.env
      ExecStart=/usr/bin/python3 /opt/decloud-blockstore/blockstore-dashboard.py
      Restart=always
      RestartSec=5
      StandardOutput=journal
      StandardError=journal

      [Install]
      WantedBy=multi-user.target

  # Bootstrap poll service — polls orchestrator for peers (primary path)
  - path: /etc/systemd/system/decloud-blockstore-bootstrap-poll.service
    permissions: '0644'
    content: |
      [Unit]
      Description=DeCloud Block Store Bootstrap Peer Polling
      After=decloud-blockstore.service network-online.target
      Wants=decloud-blockstore.service network-online.target

      [Service]
      Type=simple
      ExecStart=/usr/local/bin/blockstore-bootstrap-poll.sh
      Restart=always
      RestartSec=15
      StandardOutput=journal
      StandardError=journal

      [Install]
      WantedBy=multi-user.target

  # ── Nginx reverse proxy ──────────────────────────────────────────

  - path: /etc/nginx/sites-available/blockstore-proxy
    permissions: '0644'
    content: |
      server {
          listen 80 default_server;
          listen [::]:80 default_server;

          server_name _;

          # Nginx health check (fast, no proxy)
          location = /nginx-health {
              return 200 ""OK\n"";
              add_header Content-Type text/plain;
          }

          # Dashboard root → Python server
          location / {
              proxy_pass http://127.0.0.1:8080;
              proxy_set_header Host $host;
              proxy_set_header X-Real-IP $remote_addr;
              proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
              proxy_connect_timeout 5s;
              proxy_read_timeout 10s;
          }

          # Direct proxy for /health and /stats — bypasses Python for fast checks
          location ~ ^/(health|stats)$ {
              proxy_pass http://127.0.0.1:__BLOCKSTORE_API_PORT__;
              proxy_set_header Host $host;
          }
      }

# =====================================================
# RUNTIME COMMANDS
# =====================================================
runcmd:
  # QEMU guest agent (static unit — systemctl enable fails silently on Debian)
  - ln -sf /lib/systemd/system/qemu-guest-agent.service /etc/systemd/system/multi-user.target.wants/qemu-guest-agent.service
  - systemctl start qemu-guest-agent || true

  # ── BlockStore identity (from obligation state — persistent across redeployments) ──
  - |
    GATEWAY=$(ip route 2>/dev/null | awk '/default/ {print $3; exit}')
    ATTEMPTS=0
    IDENTITY=""""
    while [ $ATTEMPTS -lt 24 ] && [ -z ""$IDENTITY"" ]; do
      IDENTITY=$(curl -sf --max-time 5 \
        ""http://${GATEWAY}:5100/api/obligations/blockstore/state"" 2>/dev/null || echo """")
      if [ -z ""$IDENTITY"" ]; then
        echo ""Obligation state not ready — retrying in 5s (attempt $((ATTEMPTS+1))/24)""
        sleep 5
        ATTEMPTS=$((ATTEMPTS+1))
      fi
    done
    if [ -z ""$IDENTITY"" ]; then
      echo ""FATAL: BlockStore identity unavailable after 2 minutes""
      exit 1
    fi
    mkdir -p /var/lib/decloud-blockstore && chmod 700 /var/lib/decloud-blockstore
    echo ""$IDENTITY"" | jq -r '.ed25519PrivateKeyBase64' | base64 -d \
      > /var/lib/decloud-blockstore/identity.key
    chmod 600 /var/lib/decloud-blockstore/identity.key
    STORAGE_BYTES=$(echo ""$IDENTITY"" | jq -r '.storageQuotaBytes // 0')
    if [ ""$STORAGE_BYTES"" -gt 0 ]; then
      echo ""BLOCKSTORE_STORAGE_BYTES=${STORAGE_BYTES}"" >> /etc/decloud-blockstore/blockstore.env
    fi
    echo ""BlockStore identity loaded (peer: $(echo ""$IDENTITY"" | jq -r '.peerId // ""unknown""'))""

  # ── Artifacts from local cache (pre-fetched by node agent before deploy) ──
  - curl -sf ${ARTIFACT_URL:blockstore-node} -o /usr/local/bin/blockstore-node
  - echo ""${ARTIFACT_SHA256:blockstore-node}  /usr/local/bin/blockstore-node"" | sha256sum -c -
  - chmod +x /usr/local/bin/blockstore-node
  - curl -sf ${ARTIFACT_URL:wg-mesh-enroll} -o /usr/local/bin/wg-mesh-enroll.sh && chmod +x /usr/local/bin/wg-mesh-enroll.sh
  - curl -sf ${ARTIFACT_URL:wg-config-fetch} -o /usr/local/bin/wg-config-fetch.sh && chmod +x /usr/local/bin/wg-config-fetch.sh
  - curl -sf ${ARTIFACT_URL:blockstore-health-check} -o /usr/local/bin/blockstore-health-check.sh && chmod +x /usr/local/bin/blockstore-health-check.sh
  - curl -sf ${ARTIFACT_URL:blockstore-notify-ready} -o /usr/local/bin/blockstore-notify-ready.sh && chmod +x /usr/local/bin/blockstore-notify-ready.sh
  - curl -sf ${ARTIFACT_URL:blockstore-bootstrap-poll} -o /usr/local/bin/blockstore-bootstrap-poll.sh && chmod +x /usr/local/bin/blockstore-bootstrap-poll.sh
  - mkdir -p /opt/decloud-blockstore/static
  - curl -sf ${ARTIFACT_URL:blockstore-dashboard} -o /opt/decloud-blockstore/blockstore-dashboard.py && chmod +x /opt/decloud-blockstore/blockstore-dashboard.py
  - curl -sf ${ARTIFACT_URL:blockstore-dashboard-html} -o /opt/decloud-blockstore/static/dashboard.html
  - curl -sf ${ARTIFACT_URL:blockstore-dashboard-css} -o /opt/decloud-blockstore/static/dashboard.css
  - curl -sf ${ARTIFACT_URL:blockstore-dashboard-js} -o /opt/decloud-blockstore/static/dashboard.js

  # WireGuard mesh enrollment — polls NodeAgent until relay is assigned.
  # Handles CGNAT nodes where CgnatInfo may not be available at deploy time.
  # Also updates BLOCKSTORE_ADVERTISE_IP with the tunnel IP once obtained.
  - |
    export DECLOUD_ROLE=blockstore
    export NODE_ID=__NODE_ID__
    export VM_ID=__VM_ID__
    /usr/local/bin/wg-config-fetch.sh

  # Runtime data directory (not created by write_files)
  - mkdir -p /var/lib/decloud-blockstore

  # Single daemon-reload after all write_files are complete
  - systemctl daemon-reload

  # Open bitswap port for cross-region blockstore connections
  - ufw allow __BLOCKSTORE_LISTEN_PORT__/tcp comment ""DeCloud BlockStore Bitswap"" || true

  # Nginx
  - ln -sf /etc/nginx/sites-available/blockstore-proxy /etc/nginx/sites-enabled/
  - rm -f /etc/nginx/sites-enabled/default
  - nginx -t
  - systemctl enable nginx && systemctl restart nginx

  # Block store node
  - systemctl enable decloud-blockstore && systemctl start decloud-blockstore

  # Dashboard
  - systemctl enable decloud-blockstore-dashboard && systemctl start decloud-blockstore-dashboard

  # Bootstrap poll (primary orchestrator communication)
  - systemctl enable decloud-blockstore-bootstrap-poll && systemctl start decloud-blockstore-bootstrap-poll

  # Enable WireGuard watchdog timer
  - systemctl enable wg-mesh-watchdog.timer
  - systemctl start wg-mesh-watchdog.timer

  # Log completion
  - 'echo ""BlockStore __VM_ID__ ready at $(date) — storage: __BLOCKSTORE_STORAGE_BYTES__ bytes, tunnel: __WG_TUNNEL_IP__"" >> /var/log/blockstore-bootstrap.log'

final_message: ""DeCloud Block Store Node __VM_NAME__ is ready!""
";

    private const string RELAY_CLOUD_INIT = @"
