  - rm -f /etc/machine-id /var/lib/dbus/machine-id
  - systemd-machine-id-setup
  # Mask snapd/LXD — unused in system VMs, adds ~50s boot delay
  - systemctl mask snapd.service snapd.socket snapd.seeded.service snap.lxd.activate.service lxd.service lxd-agent.service 2>/dev/null || true

# =====================================================
# SYSTEM PACKAGES
# =====================================================
# Kept:
#   wireguard/wireguard-tools  — core relay functionality
#   nginx-core                 — port 80 host-based routing (dashboard vs CGNAT proxy)
#                                nginx-core omits unused media codec modules
#                                (libx265, libwebp, libtiff, libde265, libavif...)
#                                that the full nginx package pulls in
#   fail2ban                   — SSH brute-force + nginx flood protection
#   qemu-guest-agent           — VM readiness reporting to orchestrator
#   python3                    — relay-api.py + http-proxy.py runtime
#   curl                       — notify-orchestrator.sh callback
#   jq                         — JSON parsing in shell scripts
#   openssl                    — HMAC token computation in notify-orchestrator.sh
#   iptables-persistent        — persists WireGuard PostUp NAT rules across reboots
#
# Removed vs previous version:
#   nginx          → nginx-core  (same functionality, no media codecs)
#   python3-pip    → removed     (no pip installs at runtime)
#   htop           → removed     (interactive tool, unused in headless VM)
#   iftop          → removed     (interactive tool, unused in headless VM)
#   net-tools      → removed     (ifconfig/netstat, unused — iproute2 is default)
#   iptables-persistent → removed     (triggers an interactive **debconf prompt** during installation)
packages:
  - wireguard
  - wireguard-tools
  - nginx-light
  - fail2ban
  - qemu-guest-agent
  - python3
  - curl
  - jq
  - openssl

# =====================================================
# SYSTEM CONFIGURATION
# =====================================================
write_files:
  # WireGuard configuration (includes orchestrator as peer)
  - path: /etc/wireguard/wg-relay-server.conf
    permissions: '0600'
    content: |
      [Interface]
      # Relay server listening on all interfaces
      # Each relay gets unique subnet: 10.20.{1-254}.0/24
      # This relay's subnet: __RELAY_SUBNET__
      Address = 10.20.__RELAY_SUBNET__.254/24
      PrivateKey = __WIREGUARD_PRIVATE_KEY__
      ListenPort = 51820
      
      # Enable IP forwarding
      PostUp = iptables -A FORWARD -i wg-relay-server -j ACCEPT
      PostUp = iptables -A FORWARD -o wg-relay-server -j ACCEPT
      PostUp = bash -c 'DEFAULT_IFACE=$(ip route | grep default | awk ""{print \$5}""); iptables -t nat -A POSTROUTING -o $DEFAULT_IFACE -j MASQUERADE'
      # Block SSH to relay VM via tunnel (prevents interception of forwarded SSH)
      PostUp = iptables -A INPUT -i wg-relay-server -p tcp --dport 22 -j DROP
      PreDown = iptables -D FORWARD -i wg-relay-server -j ACCEPT
      PreDown = iptables -D FORWARD -o wg-relay-server -j ACCEPT
      PreDown = bash -c 'DEFAULT_IFACE=$(ip route | grep default | awk ""{print \$5}""); iptables -t nat -D POSTROUTING -o $DEFAULT_IFACE -j MASQUERADE'
      PreDown = iptables -D INPUT -i wg-relay-server -p tcp --dport 22 -j DROP
      
      # Orchestrator peer (pre-configured during provisioning)
      [Peer]
      # DeCloud Orchestrator
      PublicKey = __ORCHESTRATOR_PUBLIC_KEY__
      Endpoint = __ORCHESTRATOR_IP__:__ORCHESTRATOR_PORT__
      # Orchestrator always uses 10.20.0.1, not per-subnet IP
      AllowedIPs = 10.20.0.1/32
      PersistentKeepalive = 25
      
      # NOTE: CGNAT nodes will be added dynamically by relay API

  # Store relay private key separately
  - path: /etc/wireguard/private.key
    permissions: '0600'
    content: |
      __WIREGUARD_PRIVATE_KEY__

  # Store relay public key
  - path: /etc/wireguard/public.key
    permissions: '0644'
    content: |
      __WIREGUARD_PUBLIC_KEY__

  # Store relay subnet for reference
  - path: /etc/decloud/relay-subnet
    permissions: '0644'
    content: |
      __RELAY_SUBNET__

  # Nginx reverse proxy configuration
  # Port 80 multiplexes two services based on Host header:
  #   relay-* hostname or bare IP  → relay-api:8080 (dashboard)
  #   any other hostname           → http-proxy:8081 (CGNAT VM traffic)
  - path: /etc/nginx/sites-available/relay-proxy
    permissions: '0644'
    content: |
      # WebSocket upgrade header mapping
      map $http_upgrade $connection_upgrade {
          default upgrade;
          '' close;
      }

      # HTTP proxy for CGNAT node traffic
      server {
          listen 80 default_server;
          listen [::]:80 default_server;
    
          server_name _;
    
          # Health check
          location /health {
              return 200 ""OK\n"";
              add_header Content-Type text/plain;
          }

          # Static files (dashboard CSS/JS) → Relay API
          location /static/ {
              proxy_pass http://127.0.0.1:8080;
              proxy_set_header Host $host;
              proxy_set_header X-Real-IP $remote_addr;
              proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
              proxy_set_header X-Forwarded-Proto $scheme;
        
              # Cache static files
              proxy_cache_valid 200 1h;
              add_header Cache-Control ""public, max-age=3600"";
          }

          # Relay API dashboard (explicit path)
          location /api/relay/ {
              proxy_pass http://127.0.0.1:8080;
              proxy_set_header Host $host;
              proxy_set_header X-Real-IP $remote_addr;
              proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
              proxy_set_header X-Forwarded-Proto $scheme;
          }

          # Dashboard root (only for relay dashboard hostname)
          location = / {
              # If accessing relay directly (not a VM subdomain), show dashboard
              if ($host ~* ""^[0-9.]+$|^relay-"") {
                  proxy_pass http://127.0.0.1:8080;
                  break;
              }
        
              # Otherwise, proxy to VM
              proxy_pass http://127.0.0.1:8081;
              proxy_set_header Host $host;
              proxy_set_header X-Real-IP $remote_addr;
              proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
              proxy_set_header X-Forwarded-Proto $scheme;
        
              # Long timeout for VM traffic
              proxy_connect_timeout 30s;
              proxy_send_timeout 90s;
              proxy_read_timeout 90s;
          }

          # All wildcard subdomain traffic → HTTP Proxy Service
          location / {
              proxy_pass http://127.0.0.1:8081;
              proxy_set_header Host $host;
              proxy_set_header X-Real-IP $remote_addr;
              proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
              proxy_set_header X-Forwarded-Proto $scheme;
        
              # Timeouts
              proxy_connect_timeout 30s;
              proxy_send_timeout 90s;
              proxy_read_timeout 90s;
        
              # Buffering
              proxy_buffering off;
              proxy_request_buffering off;
        
              # WebSocket support
              proxy_http_version 1.1;
              proxy_set_header Upgrade $http_upgrade;
              proxy_set_header Connection $connection_upgrade;
          }
      }

  # fail2ban jails for relay VM threat surface:
  #   [sshd]            — SSH brute-force on public interface
  #                       (daemon still runs even though keys/passwords disabled;
  #                        connection floods consume resources)
  #   [nginx-botsearch] — scanner/bot flood on port 80
  #   [nginx-limit-req] — HTTP request rate limiting
  - path: /etc/fail2ban/jail.d/relay.conf
    permissions: '0644'
    content: |
      [sshd]
      enabled = true
      port = 22
      maxretry = 3
      bantime = 3600
      findtime = 600

      [nginx-botsearch]
      enabled = true
      port = 80
      maxretry = 2
      bantime = 86400
      findtime = 60

      [nginx-limit-req]
      enabled = true
      port = 80
      maxretry = 20
      bantime = 600
      findtime = 60
      logpath = /var/log/nginx/error.log

  # Ensure wg-quick@wg-relay-server restarts on failure at boot time.
  # WireGuardWatchdogThread in relay-api.py handles mid-run failures,
  # but systemd must handle the case where wg-quick fails before relay-api.py starts.
  - path: /etc/systemd/system/wg-quick@wg-relay-server.service.d/restart.conf
    permissions: '0644'
    content: |
      [Service]
      Restart=on-failure
      RestartSec=10

  # Relay management API systemd service
  - path: /etc/systemd/system/decloud-relay-api.service
    permissions: '0644'
    content: |
      [Unit]
      Description=DeCloud Relay Management API
      After=network.target wg-quick@wg-relay-server.service
      Wants=wg-quick@wg-relay-server.service
      
      [Service]
      Type=simple
      Restart=always
      RestartSec=5
      WorkingDirectory=/opt/decloud-relay
      ExecStart=/usr/bin/python3 /opt/decloud-relay/relay-api.py
      StandardOutput=journal
      StandardError=journal
      
      [Install]
      WantedBy=multi-user.target

  # HTTP Proxy systemd service
  - path: /etc/systemd/system/decloud-relay-http-proxy.service
    permissions: '0644'
    content: |
      [Unit]
      Description=DeCloud Relay HTTP Proxy
      After=network.target wg-quick@wg-relay-server.service nginx.service
      Wants=wg-quick@wg-relay-server.service nginx.service

      [Service]
      Type=simple
      Restart=always
      RestartSec=5
      WorkingDirectory=/opt/decloud-relay
      ExecStart=/usr/bin/python3 /opt/decloud-relay/http-proxy.py
      StandardOutput=journal
      StandardError=journal

      [Install]
      WantedBy=multi-user.target

  # NAT callback systemd service
  - path: /etc/systemd/system/decloud-relay-nat-callback.service
    permissions: '0644'
    content: |
      [Unit]
      Description=DeCloud Relay NAT Configuration Callback
      After=network-online.target
      Wants=network-online.target
      
      [Service]
      Type=oneshot
      ExecStartPre=/bin/bash -c 'if [ -f /var/lib/decloud/nat-callback-complete ]; then echo ""NAT callback already completed""; exit 0; fi'
      ExecStart=/usr/local/bin/notify-nat-ready.sh
      ExecStartPost=/bin/bash -c 'mkdir -p /var/lib/decloud && touch /var/lib/decloud/nat-callback-complete'
      RemainAfterExit=yes
      StandardOutput=journal
      StandardError=journal
      Restart=on-failure
      RestartSec=5s
      StartLimitBurst=3
      TimeoutStartSec=30s
      
      [Install]
      WantedBy=multi-user.target

  # Orchestrator registration polling service.
  # Replaces the one-shot notify-orchestrator.sh (--retry 3) that gave up permanently
  # if the orchestrator was offline during installation. This service retries every 30s
  # until it receives HTTP 200, then exits cleanly — systemd will not restart a clean exit.
  - path: /etc/systemd/system/decloud-relay-register.service
    permissions: '0644'
    content: |
      [Unit]
      Description=DeCloud Relay Orchestrator Registration
      After=decloud-relay-nat-callback.service decloud-relay-api.service
      Requires=decloud-relay-nat-callback.service

      [Service]
      Type=simple
      ExecStart=/usr/local/bin/relay-register-poll.sh
      Restart=on-failure
      RestartSec=30s
      StartLimitInterval=0
      StandardOutput=journal
      StandardError=journal

      [Install]
      WantedBy=multi-user.target

  # Registration polling script — loops until orchestrator confirms (HTTP 200).
  # Auth pattern mirrors dht-bootstrap-poll.sh: HMAC-SHA256(wg_private_key, nodeId:vmId).
  - path: /usr/local/bin/relay-register-poll.sh
    permissions: '0755'
    content: |
      #!/bin/bash
      set -euo pipefail

      ORCHESTRATOR_URL=""__ORCHESTRATOR_URL__""
      NODE_ID=""__NODE_ID__""
      RELAY_VM_ID=""__VM_ID__""
      PUBLIC_IP=""__PUBLIC_IP__""

      # Read from files written by runcmd obligation state fetch —
      # guaranteed to reflect the actual running keypair and subnet.
      PUBLIC_KEY=$(cat /etc/wireguard/public.key | tr -d '\n')
      RELAY_SUBNET=$(cat /etc/decloud/relay-subnet | tr -d '\n')
      TUNNEL_IP=""10.20.${RELAY_SUBNET}.254""
      MARKER=""/var/lib/decloud/relay-registered""
      LOG=""/var/log/decloud-relay-register.log""

      log() { echo ""[$(date +'%Y-%m-%d %H:%M:%S')] relay-register: $*"" | tee -a ""$LOG""; }

      # Idempotency guard — clean exit so systemd doesn't restart
      if [ -f ""$MARKER"" ]; then
          log ""Already registered — exiting""
          exit 0
      fi

      WIREGUARD_PRIVATE_KEY=$(cat /etc/wireguard/private.key | tr -d '\n')
      MESSAGE=""${NODE_ID}:${RELAY_VM_ID}""
      TOKEN=$(echo -n ""$MESSAGE"" | openssl dgst -sha256 -hmac ""$WIREGUARD_PRIVATE_KEY"" -binary | base64)

      log ""Starting orchestrator registration poll (will retry until success)...""

      while true; do
          HTTP=$(curl -s -o /tmp/relay-register-resp.json -w ""%{http_code}"" \
              -X POST ""$ORCHESTRATOR_URL/api/relay/register-callback"" \
              -H ""Content-Type: application/json"" \
              -H ""X-Relay-Token: $TOKEN"" \
              -d ""{
                  \""nodeId\"": \""$NODE_ID\"",
                  \""relayVmId\"": \""$RELAY_VM_ID\"",
                  \""wireGuardPublicKey\"": \""$PUBLIC_KEY\"",
                  \""wireGuardEndpoint\"": \""$PUBLIC_IP:51820\"",
                  \""relaySubnet\"": $RELAY_SUBNET,
                  \""tunnelIp\"": \""$TUNNEL_IP\""
              }"" \
              --max-time 15 2>/dev/null || echo ""000"")

          if [ ""$HTTP"" = ""200"" ]; then
              log ""Registration successful (HTTP 200)""
              mkdir -p ""$(dirname ""$MARKER"")""
              echo ""Registered at $(date)"" > ""$MARKER""
              logger -t decloud-relay ""Orchestrator registration successful""
              exit 0   # Clean exit — systemd will not restart
          elif [ ""$HTTP"" = ""401"" ] || [ ""$HTTP"" = ""403"" ]; then
              log ""Authentication failed (HTTP $HTTP) — token misconfiguration, exiting""
              exit 1   # Auth failures are config errors; systemd restart with backoff
          else
              log ""Orchestrator unreachable (HTTP ${HTTP:-timeout}) — retrying in 30s""
              sleep 30
          fi
      done

  # Relay metadata JSON
  - path: /etc/decloud/relay-metadata.json
    permissions: '0644'
    content: |
      {
        ""node_id"": ""__NODE_ID__"",
        ""relay_id"": ""__VM_ID__"",
        ""vm_id"": ""__VM_ID__"",
        ""relay_name"": ""__VM_NAME__"",
        ""region"": ""__RELAY_REGION__"",
        ""relay_subnet"": __RELAY_SUBNET__,
        ""tunnel_ip"": ""10.20.__RELAY_SUBNET__.254"",
        ""max_capacity"": __RELAY_CAPACITY__,
        ""wireguard_endpoint"": ""__PUBLIC_IP__:51820"",
        ""wireguard_public_key"": ""__WIREGUARD_PUBLIC_KEY__"",
        ""orchestrator_public_key"": ""__ORCHESTRATOR_PUBLIC_KEY__"",
        ""created_at"": ""__TIMESTAMP__"",
        ""version"": ""4.2""
      }

# =====================================================
# RUNTIME COMMANDS
# =====================================================
runcmd:
  # Start QEMU guest agent first so the orchestrator monitor can track progress
  - ln -sf /lib/systemd/system/qemu-guest-agent.service /etc/systemd/system/multi-user.target.wants/qemu-guest-agent.service
  - systemctl start qemu-guest-agent || true

  # Enable IP forwarding (required for relay functionality)
  - echo ""net.ipv4.ip_forward=1"" >> /etc/sysctl.conf
  - echo ""net.ipv6.conf.all.forwarding=1"" >> /etc/sysctl.conf
  - sysctl -p
  
  # Disable UFW — iptables rules are managed directly via WireGuard PostUp/PreDown
  # and iptables-persistent. UFW would interfere with WireGuard NAT rules.
  - ufw disable || true
  - systemctl stop ufw || true
  - systemctl disable ufw || true
  
  # Rewrite WireGuard config with identity from NodeAgent obligation state.
  # Ensures the relay uses its persistent keypair (not the label-baked placeholder)
  # so CGNAT nodes don't need to re-register when the relay VM is replaced.
  - |
    GATEWAY=$(ip route 2>/dev/null | awk '/default/ {print $3; exit}')
    for i in $(seq 1 24); do
      STATE=$(curl -sf --max-time 5 \
          ""http://${GATEWAY}:5100/api/obligations/relay/state"" 2>/dev/null || true)
      WG_PRIV=$(echo ""$STATE"" | jq -r '.wireGuardPrivateKey // empty' 2>/dev/null || true)
      WG_PUB=$(echo ""$STATE""  | jq -r '.wireGuardPublicKey  // empty' 2>/dev/null || true)
      SUBNET=$(echo ""$STATE""  | jq -r '.relaySubnet         // empty' 2>/dev/null || true)
      [ -n ""$WG_PRIV"" ] && break
      sleep 5
    done
    if [ -n ""$WG_PRIV"" ]; then
      # Handle ""10.20.248.0/24"" → ""248"", bare ""248"" → ""248"", empty → fallback
      if echo ""$SUBNET"" | grep -qE '^[0-9]+$'; then
        SUBNET_OCTET=""$SUBNET""
      else
        SUBNET_OCTET=$(echo ""$SUBNET"" | cut -d'.' -f3)
      fi
      [ -z ""$SUBNET_OCTET"" ] && SUBNET_OCTET=$(cat /etc/decloud/relay-subnet 2>/dev/null | tr -d '\n')
      [ -z ""$SUBNET_OCTET"" ] && SUBNET_OCTET=""248""
      sed -i \
          -e ""s|^PrivateKey = .*|PrivateKey = ${WG_PRIV}|"" \
          -e ""s|^Address = .*|Address = 10.20.${SUBNET_OCTET}.254/24|"" \
          /etc/wireguard/wg-relay-server.conf
      printf '%s\n' ""$WG_PRIV"" > /etc/wireguard/private.key
      printf '%s\n' ""$WG_PUB""  > /etc/wireguard/public.key

      # Update relay-subnet file so routes runcmd and relay-register-poll.sh
      # read the obligation-state subnet, not the label-baked placeholder
      printf '%s\n' ""$SUBNET_OCTET"" > /etc/decloud/relay-subnet

      # Patch relay-metadata.json with correct values from obligation state
      if [ -f /etc/decloud/relay-metadata.json ]; then
        sed -i \
            -e ""s|\""wireguard_public_key\"": \""[^\""]*\""|\""wireguard_public_key\"": \""${WG_PUB}\""|"" \
            -e ""s|\""relay_subnet\"": [0-9]*|\""relay_subnet\"": ${SUBNET_OCTET}|"" \
            -e ""s|\""tunnel_ip\"": \""[^\""]*\""|\""tunnel_ip\"": \""10.20.${SUBNET_OCTET}.254\""|"" \
            /etc/decloud/relay-metadata.json
      fi

      echo ""Relay identity updated from obligation state (pubkey: $(printf '%.16s' ""$WG_PUB"")..., subnet: ${SUBNET_OCTET})""
    else
      echo ""WARNING: NodeAgent obligation state unavailable — using label-baked WG key""
    fi

  - systemctl enable wg-quick@wg-relay-server
  - systemctl start wg-quick@wg-relay-server

  # Verify orchestrator peer is configured
  - wg show wg-relay-server | grep -A 5 ""__ORCHESTRATOR_PUBLIC_KEY__"" || echo ""WARNING - Orchestrator peer not found!""

  # Configure routes for relay subnet — read from file updated by obligation state fetch
  - |
    RELAY_SUBNET=$(cat /etc/decloud/relay-subnet 2>/dev/null | tr -d '\n' || echo ""__RELAY_SUBNET__"")
    echo ""Configuring routes for relay subnet ${RELAY_SUBNET}...""
    ip route add 10.20.${RELAY_SUBNET}.0/24 dev wg-relay-server 2>/dev/null || echo ""Route already exists""
    mkdir -p /etc/network
    echo ""10.20.${RELAY_SUBNET}.0/24 dev wg-relay-server scope link"" >> /etc/network/routes 2>/dev/null || true
    echo ""Routes configured for subnet 10.20.${RELAY_SUBNET}.0/24""

  # Wait for WireGuard to be fully up
  - |
    for i in $(seq 1 10); do
      if wg show wg-relay-server &>/dev/null; then
        echo ""WireGuard interface ready""
        break
      fi
      sleep 2
    done

  # Start NAT callback service.
  # notify-nat-ready.sh (downloaded from artifact cache above) starts
  # decloud-relay-register.service on completion instead of calling
  # the old one-shot notify-orchestrator.sh.
  # ── Artifacts from local cache (pre-fetched by node agent before deploy) ──
  # Must run BEFORE any service that references these scripts.
  - mkdir -p /opt/decloud-relay/static /etc/decloud
  - curl -sf ${ARTIFACT_URL:relay-api} -o /opt/decloud-relay/relay-api.py && chmod +x /opt/decloud-relay/relay-api.py
  - curl -sf ${ARTIFACT_URL:relay-http-proxy} -o /opt/decloud-relay/http-proxy.py && chmod +x /opt/decloud-relay/http-proxy.py
  - curl -sf ${ARTIFACT_URL:notify-nat-ready} -o /usr/local/bin/notify-nat-ready.sh && chmod +x /usr/local/bin/notify-nat-ready.sh
  - curl -sf ${ARTIFACT_URL:relay-dashboard-html} -o /opt/decloud-relay/static/dashboard.html
  - curl -sf ${ARTIFACT_URL:relay-dashboard-css} -o /opt/decloud-relay/static/dashboard.css
  - curl -sf ${ARTIFACT_URL:relay-dashboard-js} -o /opt/decloud-relay/static/dashboard.js

  - systemctl daemon-reload
  - systemctl enable decloud-relay-nat-callback.service
  - systemctl start decloud-relay-nat-callback.service
  - systemctl enable decloud-relay-register
  - systemctl start decloud-relay-register || true

  # Configure and start Nginx
  - ln -sf /etc/nginx/sites-available/relay-proxy /etc/nginx/sites-enabled/
  - rm -f /etc/nginx/sites-enabled/default
  - nginx -t
  - systemctl enable nginx
  - systemctl restart nginx

  # Start relay services
  - systemctl daemon-reload
  - systemctl enable decloud-relay-http-proxy
  - systemctl start decloud-relay-http-proxy
  - sleep 2
  - systemctl is-active decloud-relay-http-proxy || echo ""WARNING - HTTP proxy failed to start""
  
  - systemctl enable decloud-relay-api
  - systemctl start decloud-relay-api
  - systemctl is-active decloud-relay-api || echo ""WARNING - Relay API failed to start""

  # Start fail2ban (jails configured in write_files above)
  - systemctl enable fail2ban
  - systemctl start fail2ban
  
  # Log completion
  - 'echo ""DeCloud relay VM bootstrap complete at $(date)"" >> /var/log/decloud-relay-bootstrap.log'
  - 'echo ""Relay ID: __VM_ID__"" >> /var/log/decloud-relay-bootstrap.log'
  - 'echo ""Relay Subnet: __RELAY_SUBNET__ (10.20.__RELAY_SUBNET__.0/24)"" >> /var/log/decloud-relay-bootstrap.log'
  - 'echo ""Tunnel IP: 10.20.__RELAY_SUBNET__.254"" >> /var/log/decloud-relay-bootstrap.log'
  - 'echo ""Region: __RELAY_REGION__"" >> /var/log/decloud-relay-bootstrap.log'

final_message: ""DeCloud Relay VM __VM_NAME__ is ready! Subnet: 10.20.__RELAY_SUBNET__.0/24, Gateway: 10.20.__RELAY_SUBNET__.254""
";
}
